// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// STRY0112991
	g_scratchpad.isDraftScheduleFeatureEnabled = new tasking_System_Settings_Scripts().isDraftScheduleFeatureEnabled();

	// only set values if this is a new record
	if(!current.isNewRecord()){
		return;
	}

	// NOTE: this replaces functions in TaskTemplateHelpers
	// - createEmptyTemplateFieldsJSON
	// - loadTemplateAndTaskIntoInstanceForm
	// - loadTemplateIntoInstanceForm
	// - loadTemplateInputsFromDataFields
	// - loadInputDefaultFromTemplate (NOTE: this one might still be used when called from API, double check it)
	// for each field that can be in the input, see if the associated Template field has a value.
	// if the associated tempalte has a value, the set the field to the template field.
	var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
	var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
	var templateID = current.routing_template_ref + '';
	var parentTaskID = current.parent_task + '';
	if(grTemp.get(templateID)){
		// STRY0112991
		current.u_create_tasks_in_draft_state = grTemp.getValue("u_create_tasks_in_draft_state");

		current.discover_template_name = grTemp.template_name + '';

		current.short_description = grTemp.getValue("short_description");
		// STRY0085139 - pull classification from the template instead of Task
		current.classification = grTemp.getValue("classification");

		// STRY0084306
		current.u_template_subtask_s_name_setting = grTemp.getValue("u_template_subtask_s_name_setting");
		// STRY0084419, STRY0084420, STRY0084424
		current.u_subtask_s_name_modifier = '';

		current.instance_notation = grTemp.getValue("description");

		// STRY0075864
		current.u_external_ou = grTemp.getValue("u_external_ou");

		current.poc_name = grTemp.getValue("poc_name");
		current.outbound = (grTemp.outbound == true) ? 'true' : 'false';
		current.u_internal_contact = grTemp.getValue("u_internal_contact");
		current.u_internal_contact_performing_task = (grTemp.u_internal_contact_performing_task == true) ? 'true' : 'false';
		// STRY0085139 
		current.u_on_behalf_of = grTemp.u_on_behalf_of +'';
		// everything in parent task block is set by the parent below when the parent is set
		if(parentTaskID == ''){
			current.u_objective = grTemp.u_objective + '';
			current.u_restricted_group = grTemp.u_restricted_group + '';
			current.u_tasking_authority = grTemp.u_tasking_authority + '';
			current.u_primary_office = grTemp.u_primary_office + '';
			current.u_primary_assignee = grTemp.u_primary_assignee +'';
			current.u_assigned_member = grTemp.u_assigned_member +'';
			current.u_reviewer = grTemp.getValue("u_reviewer");
			current.originator = gs.getUserID();
		}

		// simplify template run, remove workflow
		// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
		current = new CustomTaskerFieldHelper().mapFieldDataOnAction('TemplateInstanceOnLoadDeaultFromTemplate', grTemp, current);		
	}
	if(parentTaskID != '' && grTask.get(parentTaskID)){
		// Laod the fields coming from the Parent Task
		current.parent_task = parentTaskID;
		// STRY0085139 - pull classification from the template instead of Task
		//current.classification = grTask.getValue("classification");

		current.u_objective = grTask.u_objective + '';

		current.u_restricted_group = grTask.assignment_group + '';
		current.u_tasking_authority = grTask.tasking_authority + '';
		current.u_primary_office = grTask.primary_office + '';
		current.u_primary_assignee = grTask.primary_assignee +'';
		current.u_assigned_member = grTask.assigned_to +'';

		// STRY0085139 
		current.u_reviewer = grTask.u_reviewer +'';

		current.originator = gs.getUserID();
		// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
		current = new CustomTaskerFieldHelper().mapFieldDataOnAction('TemplateInstanceOnLoadDeaultFromTask', grTask, current);		
	}
})(current, previous);
